function solve(s) {
    const segments = [];
    const seen = new Set();
    let current = '';
    for (const char of s) {
        current += char;
        if (!seen.has(current)) {
            segments.push(current);
            seen.add(current);
            current = '';
        }
    }
    return segments;
}
